import 'dart:async';

import '../lib/worker.dart';

Future<void> main() async {
  final events = <String>[];
  final controller = StreamController<String>(sync: true);
  final worker = EventWorker(events.add);
  worker.start(controller.stream);
  controller.add('before');
  await worker.stop();
  controller.add('after');
  await controller.close();
  if (events.join(',') != 'before') {
    throw StateError('stopped worker dispatched: ${events.join(',')}');
  }
  print('hidden worker contract passed');
}
